    11→import { prisma } from '@/lib/db';
    12→import { logger } from '@/lib/logger';
    13→
    14→// #92: Zod schema for settings validation
    15→const SettingsUpdateSchema = z.object({
    16→  theme: z.enum(['light', 'dark', 'system']).optional(),
    17→  language: z.string().max(10).optional(),
    18→  accentColor: z.string().max(20).optional(),
    19→  provider: z.enum(['azure', 'ollama']).optional(),  // #89: Only valid providers
    20→  model: z.string().max(50).optional(),
    21→  budgetLimit: z.number().min(0).max(10000).optional(),
    22→  totalSpent: z.number().min(0).optional(),  // #88: Now accepted
    23→  // Accessibility
    24→  fontSize: z.enum(['small', 'medium', 'large', 'extra-large']).optional(),
    25→  highContrast: z.boolean().optional(),
    26→  dyslexiaFont: z.boolean().optional(),
    27→  reducedMotion: z.boolean().optional(),
    28→  voiceEnabled: z.boolean().optional(),
    29→  simplifiedLanguage: z.boolean().optional(),
    30→  adhdMode: z.boolean().optional(),
    31→}).strict();  // Reject unknown fields
