    34→  try {
    35→    const cookieStore = await cookies();
    36→    const userId = cookieStore.get('convergio-user-id')?.value;
    37→
    38→    if (!userId) {
    39→      return NextResponse.json({ error: 'No user' }, { status: 401 });
    40→    }
    41→
    42→    let settings = await prisma.settings.findUnique({
    43→      where: { userId },
    44→    });
    45→
    46→    if (!settings) {
    47→      // Create default settings
    48→      settings = await prisma.settings.create({
    49→        data: { userId },
    50→      });
    51→    }
    52→
    53→    return NextResponse.json(settings);
    54→  } catch (error) {
    55→    logger.error('Settings GET error', { error: String(error) });
